import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import bcrypt from "bcryptjs";
import path from "path";
import fs from "fs";
import { writeFile } from "fs/promises";
import pdfParse from "pdf-parse";
import OpenAI from "openai";
import nodemailer from "nodemailer";

const openai = new OpenAI({
  apiKey: process.env.OPENAI_API_KEY,
});

const generateOTP = () => Math.floor(1000 + Math.random() * 9000).toString();

export const config = {
  api: {
    bodyParser: {
      sizeLimit: "10mb",
    },
  },
};

const uploadDir = path.join(process.cwd(), "public/uploads");
if (!fs.existsSync(uploadDir)) {
  fs.mkdirSync(uploadDir, { recursive: true });
}

const saveFile = async (file: File) => {
  const fileName = `${Date.now()}-${file.name.replace(/\s+/g, "_")}`;
  const filePath = path.join(uploadDir, fileName);

  const bytes = await file.arrayBuffer();
  const buffer = Buffer.from(bytes);

  await writeFile(filePath, buffer);
  return filePath;
};

// Extract raw text from PDF
const extractTextFromPDF = async (filePath: string) => {
  const dataBuffer = fs.readFileSync(filePath);
  const pdfData = await pdfParse(dataBuffer);
  return pdfData.text.replace(/\s+/g, " ").trim();
};

// AI Processing to Structure Data
const analyzePDFTextWithAI = async (text: string) => {
  const prompt = `
  Extract the following information from the provided text:
  - Full Name
  - Marks and Subjects
  - Percentage
  - Board
  - Any other relevant details.

  Provide a structured JSON format. Here is the text extracted from a student’s PDF:

  """${text}"""
  `;

  const response = await openai.chat.completions.create({
    model: "gpt-4-turbo",
    messages: [{ role: "system", content: "You are a smart AI that extracts structured data from PDFs." }, { role: "user", content: prompt }],
    temperature: 0.5,
  });

  console.log("AI Response:", response);

  return JSON.parse(response.choices[0].message.content);
};

const transporter = nodemailer.createTransport({
  host: process.env.EMAIL_HOST,
  port: Number(process.env.EMAIL_PORT),
  secure: process.env.EMAIL_PORT === "465",
  auth: {
    user: process.env.EMAIL_USER,
    pass: process.env.EMAIL_PASS,
  },
});

export async function POST(req: Request) {
  try {
    const formData = await req.formData();
    const name = formData.get("name") as string;
    const email = formData.get("email") as string;
    const password = formData.get("password") as string;
    const phone_number = formData.get("phone_number") as string;
    const country_id = Number(formData.get("country_id"));
    const program_id = Number(formData.get("program_id"));
    const university_id = Number(formData.get("university_id"));
    const id_proof = formData.get("id_proof") as string;

    if (!id_proof) {
      return NextResponse.json({ error: "id_proof is required" }, { status: 400 });
    }

    const requiredFiles = ["tenth_certificate", "twelfth_certificate"];
    const extractedData: any = {};

    for (const fileKey of requiredFiles) {
      const file = formData.get(fileKey) as File;
      if (!file) {
        return NextResponse.json({ error: `${fileKey} is required` }, { status: 400 });
      }
      if (!file.name.toLowerCase().endsWith(".pdf")) {
        return NextResponse.json({ error: `${fileKey} must be a PDF` }, { status: 400 });
      }

      const filePath = await saveFile(file);

      // Extract and analyze PDF data
      const rawText = await extractTextFromPDF(filePath);
      extractedData[fileKey] = await analyzePDFTextWithAI(rawText);
    }

    const hashedPassword = await bcrypt.hash(password, 10);
    const otp = generateOTP();
    const otpExpiry = new Date(Date.now() + 10 * 60 * 1000);

    await db.query(
      `INSERT INTO users (name, email, password, phone_number, country_id, program_id, university_id, id_proof, otp, otp_expires_at, tenth_certificate, twelfth_certificate, extracted_data) 
     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?);`,
      [
        name,
        email,
        hashedPassword,
        phone_number,
        country_id,
        program_id,
        university_id,
        id_proof,
        otp,
        otpExpiry,
        extractedData.tenth_certificate,
        extractedData.twelfth_certificate,
        JSON.stringify(extractedData), // Store structured data
      ]
    );

    try {
      await transporter.sendMail({
        from: process.env.EMAIL_USER,
        to: email,
        subject: "Your OTP for Registration",
        html: `
          <p>Dear <strong>${name}</strong>,</p>
          <p>Your OTP for registration is: <strong>${otp}</strong></p>
          <p>This OTP is valid for 10 minutes.</p>
          <p>Best Regards,<br><strong>BringUrBuddy Team</strong></p>
        `,
      });
    } catch (emailError) {
      console.error("Email Sending Error:", emailError);
      return NextResponse.json({ error: "User registered but failed to send OTP email." }, { status: 500 });
    }

    return NextResponse.json({
      message: "Success",
      extractedData,
    }, { status: 201 });

  } catch (error) {
    console.error("Registration Error:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}
